import React, { useState, useMemo, useCallback, useEffect, useRef } from 'react';
import { View } from 'react-native';
import type {
  SDUIScreen,
  SDUIComponent,
  SDUIComponentRegistry,
  SDUIComponentProps,
  SDUIContext,
  SDUIConditional,
  SDUIActionDescriptor,
  SDUIActionRegistry,
  SDUIActionDeps,
  SDUIActionContext,
} from '../models';
import { interpolateDeep } from '../utils/interpolation';
import { evaluateRule } from '../utils/jsonLogic';
import { getDefaultRegistry, getRenderer } from '../registry';
import { executeAction, executeActions } from '../actions/registry';
import FallbackComponent from './FallbackComponent';

interface ScreenRendererProps {
  screen: SDUIScreen;
  registry?: SDUIComponentRegistry;
  actionRegistry?: SDUIActionRegistry;
  actionDeps?: Omit<SDUIActionDeps, 'signal'>;
}

function isConditional(value: unknown): value is SDUIConditional {
  return (
    value !== null &&
    typeof value === 'object' &&
    'rule' in (value as Record<string, unknown>) &&
    typeof (value as Record<string, unknown>).rule === 'object'
  );
}

function isVisible(component: SDUIComponent, context: SDUIContext): boolean {
  if (!component.visible) return true;
  const { rule } = component.visible;
  if (!rule || typeof rule !== 'object' || Object.keys(rule).length === 0) {
    return true;
  }
  return evaluateRule(rule, context);
}

function separateConditionals(props: SDUIComponentProps): {
  interpolatable: SDUIComponentProps;
  conditionals: Record<string, SDUIConditional>;
} {
  const interpolatable: SDUIComponentProps = {};
  const conditionals: Record<string, SDUIConditional> = {};

  for (const key of Object.keys(props)) {
    if (isConditional(props[key])) {
      conditionals[key] = props[key] as SDUIConditional;
    } else {
      interpolatable[key] = props[key];
    }
  }

  return { interpolatable, conditionals };
}

function renderComponent(
  component: SDUIComponent,
  context: SDUIContext,
  registry: SDUIComponentRegistry,
  key: string,
  onAction?: (descriptor: SDUIActionDescriptor) => void,
) {
  if (!isVisible(component, context)) return null;

  const { interpolatable, conditionals } = separateConditionals(component.props);
  const interpolatedProps = {
    ...interpolateDeep(interpolatable, context),
    ...conditionals,
  };

  const Renderer = getRenderer(registry, component.type);

  if (!Renderer) {
    return (
      <FallbackComponent
        key={key}
        type={component.type}
        props={interpolatedProps}
      />
    );
  }

  return (
    <Renderer
      key={key}
      props={interpolatedProps}
      context={context}
      onAction={onAction}
    />
  );
}

export default function ScreenRenderer({
