    );
    expect(getByText('Submit')).toBeTruthy();
  });

  describe('onAction integration', () => {
    function buildActionRegistry() {
      let reg = createRegistry();
      reg = registerComponent(reg, 'heading', HeadingAdapter);
      reg = registerComponent(reg, 'action_button', ActionButtonAdapter);
      reg = registerComponent(reg, 'context_display', ContextDisplayAdapter);
      return reg;
    }

    it('passes onAction to adapters when actionRegistry is provided', () => {
      const handler = jest.fn().mockReturnValue({ success: true });
      let actionReg = createActionRegistry();
      actionReg = registerAction(actionReg, 'navigate', handler);
      const compRegistry = buildActionRegistry();

      const screen: SDUIScreen = {
        id: 'action_test',
        context: { product: 'Test' },
        body: [
          {
            type: 'action_button',
            props: {
              label: 'Go',
              action: { type: 'navigate', payload: { screen: 'Home' } },
            },
          },
        ],
      };

      const { getByTestId } = render(
        <ScreenRenderer
          screen={screen}
          registry={compRegistry}
          actionRegistry={actionReg}
        />,
      );

      fireEvent.press(getByTestId('action-button'));
      expect(handler).toHaveBeenCalledTimes(1);
    });

    it('does not pass onAction when actionRegistry is not provided', () => {
      const compRegistry = buildActionRegistry();
      const screen: SDUIScreen = {
        id: 'no_action_test',
        context: {},
        body: [
          {
            type: 'action_button',
            props: {
              label: 'Go',
              action: { type: 'navigate', payload: { screen: 'Home' } },
            },
          },
        ],
      };

      const { getByTestId } = render(
        <ScreenRenderer screen={screen} registry={compRegistry} />,
      );

      // Press should not throw even without actionRegistry
      fireEvent.press(getByTestId('action-button'));
    });

    it('interpolates action payloads with merged context (screen + form)', () => {
      const handler = jest.fn().mockReturnValue({ success: true });
      let actionReg = createActionRegistry();
      actionReg = registerAction(actionReg, 'navigate', handler);
      const compRegistry = buildActionRegistry();

      const screen: SDUIScreen = {
        id: 'interpolation_test',
        context: { product: { name: 'Abastecimento' } },
        body: [
          {
            type: 'action_button',
            props: {
              label: 'Go',
              action: {
                type: 'navigate',
                payload: { screen: 'Summary', title: '{{product.name}}' },
              },
            },
          },
        ],
      };

      const { getByTestId } = render(
        <ScreenRenderer
          screen={screen}
          registry={compRegistry}
          actionRegistry={actionReg}
        />,
      );

      fireEvent.press(getByTestId('action-button'));
      expect(handler).toHaveBeenCalled();
      const callPayload = handler.mock.calls[0][0];
      expect(callPayload.title).toBe('Abastecimento');
    });

    it('merges form state into context for interpolation', () => {
      const compRegistry = buildActionRegistry();

      const screen: SDUIScreen = {
        id: 'form_context_test',
        context: { balance: 1000 },
        body: [
          {
            type: 'context_display',
            props: {},
          },
        ],
      };

      const { getByTestId } = render(
        <ScreenRenderer screen={screen} registry={compRegistry} />,
      );

      const contextText = getByTestId('context-display').props.children;
      const parsed = JSON.parse(contextText);
      expect(parsed.balance).toBe(1000);
      expect(parsed.form).toEqual({});
    });

    it('passes actionDeps to action handlers', () => {
      const handler = jest.fn().mockReturnValue({ success: true });
      let actionReg = createActionRegistry();
      actionReg = registerAction(actionReg, 'navigate', handler);
      const compRegistry = buildActionRegistry();
      const mockNavigation = {
        navigate: jest.fn(),
        goBack: jest.fn(),
        replace: jest.fn(),
      };

      const screen: SDUIScreen = {
        id: 'deps_test',
        context: {},
        body: [
          {
            type: 'action_button',
            props: {
              label: 'Go',
              action: { type: 'navigate', payload: { screen: 'Home' } },
            },
          },
        ],
      };

      const { getByTestId } = render(
        <ScreenRenderer
          screen={screen}
          registry={compRegistry}
          actionRegistry={actionReg}
          actionDeps={{ navigation: mockNavigation }}
        />,
      );

      fireEvent.press(getByTestId('action-button'));
      const callDeps = handler.mock.calls[0][2];
      expect(callDeps.navigation).toBe(mockNavigation);
      expect(callDeps.signal).toBeDefined();
    });

    it('renders without actionRegistry (backward compatibility)', () => {
      const registry = buildRegistry();
      const { getByText } = render(
        <ScreenRenderer screen={MOCK_SCREEN} registry={registry} />,
      );
      expect(getByText('Voucher para Abastecimento')).toBeTruthy();
    });
  });
});

