  const { context, header, body, footer } = screen;

  const [formState, setForm] = useState<Record<string, unknown>>({});

  const abortControllerRef = useRef<AbortController | null>(null);

  useEffect(() => {
    const controller = new AbortController();
    abortControllerRef.current = controller;
    return () => {
      controller.abort();
      abortControllerRef.current = null;
    };
  }, []);

  const mergedContext = useMemo<SDUIContext>(
