import React from 'react';
import { render, fireEvent, act } from '@testing-library/react-native';
import { Text, Pressable } from 'react-native';
import ScreenRenderer from './ScreenRenderer';
import { createRegistry, registerComponent } from '../registry';
import { createActionRegistry, registerAction } from '../actions/registry';
import type {
  SDUIScreen,
  SDUIComponentProps,
  SDUIContext,
  SDUIActionDescriptor,
  SDUIActionHandler,
} from '../models';

const HeadingAdapter = ({
  props,
}: {
  props: SDUIComponentProps;
  context: SDUIContext;
}) => <Text testID="heading">{String(props.text)}</Text>;

const ButtonAdapter = ({
  props,
}: {
  props: SDUIComponentProps;
  context: SDUIContext;
}) => <Text testID="button">{String(props.label)}</Text>;

const ActionButtonAdapter = ({
  props,
  onAction,
}: {
  props: SDUIComponentProps;
  context: SDUIContext;
  onAction?: (descriptor: SDUIActionDescriptor) => void;
}) => (
  <Pressable
    testID="action-button"
    onPress={() => {
      if (onAction && props.action) {
        onAction(props.action as unknown as SDUIActionDescriptor);
      }
    }}
  >
    <Text>{String(props.label)}</Text>
  </Pressable>
);

const ContextDisplayAdapter = ({
  props,
  context,
}: {
  props: SDUIComponentProps;
  context: SDUIContext;
}) => (
  <Text testID="context-display">
    {JSON.stringify(context)}
  </Text>
);

function buildRegistry() {
  let registry = createRegistry();
  registry = registerComponent(registry, 'heading', HeadingAdapter);
  registry = registerComponent(registry, 'button', ButtonAdapter);
  return registry;
}

const MOCK_SCREEN: SDUIScreen = {
  id: 'test_screen',
  context: {
    product: { name: 'Abastecimento' },
    balance: { pointsFormatted: '25.720' },
  },
  header: {
    type: 'heading',
    props: { text: 'Voucher para {{product.name}}' },
  },
  body: [
    {
      type: 'heading',
      props: { text: 'Saldo: {{balance.pointsFormatted}} pontos' },
    },
    {
      type: 'button',
      props: { label: 'Continuar' },
    },
  ],
  footer: {
    type: 'button',
    props: { label: 'Confirmar' },
  },
};

describe('ScreenRenderer', () => {
  it('renders header, body, and footer components', () => {
    const registry = buildRegistry();
    const { getAllByTestId } = render(
      <ScreenRenderer screen={MOCK_SCREEN} registry={registry} />,
    );
    const headings = getAllByTestId('heading');
    const buttons = getAllByTestId('button');
    expect(headings).toHaveLength(2);
    expect(buttons).toHaveLength(2);
  });

  it('applies interpolation to component props', () => {
    const registry = buildRegistry();
    const { getByText } = render(
      <ScreenRenderer screen={MOCK_SCREEN} registry={registry} />,
    );
    expect(getByText('Voucher para Abastecimento')).toBeTruthy();
    expect(getByText('Saldo: 25.720 pontos')).toBeTruthy();
  });

  it('renders fallback for unknown component types', () => {
    const registry = createRegistry();
    const screen: SDUIScreen = {
      id: 'fallback_test',
      context: {},
      body: [{ type: 'unknown_widget', props: { foo: 'bar' } }],
    };
    const { getByText } = render(
      <ScreenRenderer screen={screen} registry={registry} />,
    );
    expect(getByText(/Unknown component: "unknown_widget"/)).toBeTruthy();
  });

  it('renders without header and footer when absent', () => {
    const registry = buildRegistry();
    const screen: SDUIScreen = {
      id: 'no_header_footer',
      context: {},
      body: [{ type: 'button', props: { label: 'Only body' } }],
    };
    const { getByText, queryByText } = render(
      <ScreenRenderer screen={screen} registry={registry} />,
    );
    expect(getByText('Only body')).toBeTruthy();
    expect(queryByText('Voucher')).toBeNull();
  });

  it('handles empty body array', () => {
    const registry = buildRegistry();
    const screen: SDUIScreen = {
      id: 'empty_body',
      context: {},
      body: [],
    };
    const { toJSON } = render(
      <ScreenRenderer screen={screen} registry={registry} />,
    );
    expect(toJSON()).toBeTruthy();
  });

  it('hides component when visible rule evaluates to false', () => {
    const registry = buildRegistry();
    const screen: SDUIScreen = {
      id: 'visibility_test',
      context: { showButton: false },
      body: [
        {
          type: 'heading',
          props: { text: 'Always visible' },
        },
        {
          type: 'button',
          props: { label: 'Hidden button' },
          visible: { rule: { '==': [{ var: 'showButton' }, true] } },
        },
      ],
    };
    const { getByText, queryByText } = render(
      <ScreenRenderer screen={screen} registry={registry} />,
    );
    expect(getByText('Always visible')).toBeTruthy();
    expect(queryByText('Hidden button')).toBeNull();
  });

  it('shows component when visible rule evaluates to true', () => {
    const registry = buildRegistry();
    const screen: SDUIScreen = {
      id: 'visibility_true_test',
      context: { showButton: true },
      body: [
        {
          type: 'button',
          props: { label: 'Visible button' },
          visible: { rule: { '==': [{ var: 'showButton' }, true] } },
        },
      ],
    };
    const { getByText } = render(
      <ScreenRenderer screen={screen} registry={registry} />,
    );
    expect(getByText('Visible button')).toBeTruthy();
  });

  it('shows component when no visible property is set', () => {
    const registry = buildRegistry();
    const screen: SDUIScreen = {
      id: 'no_visible_test',
      context: {},
      body: [
        {
          type: 'heading',
          props: { text: 'No visibility rule' },
        },
      ],
    };
    const { getByText } = render(
      <ScreenRenderer screen={screen} registry={registry} />,
    );
    expect(getByText('No visibility rule')).toBeTruthy();
  });

  it('hides header when visible rule evaluates to false', () => {
    const registry = buildRegistry();
    const screen: SDUIScreen = {
      id: 'header_visibility_test',
      context: { showHeader: false },
      header: {
        type: 'heading',
        props: { text: 'Hidden header' },
        visible: { rule: { '==': [{ var: 'showHeader' }, true] } },
      },
      body: [
        { type: 'heading', props: { text: 'Body content' } },
      ],
    };
    const { queryByText, getByText } = render(
      <ScreenRenderer screen={screen} registry={registry} />,
    );
    expect(queryByText('Hidden header')).toBeNull();
    expect(getByText('Body content')).toBeTruthy();
  });

  it('hides footer when visible rule evaluates to false', () => {
    const registry = buildRegistry();
    const screen: SDUIScreen = {
      id: 'footer_visibility_test',
      context: { showFooter: false },
      body: [
        { type: 'heading', props: { text: 'Body content' } },
      ],
      footer: {
        type: 'button',
        props: { label: 'Hidden footer' },
        visible: { rule: { '==': [{ var: 'showFooter' }, true] } },
      },
    };
    const { queryByText, getByText } = render(
      <ScreenRenderer screen={screen} registry={registry} />,
    );
    expect(queryByText('Hidden footer')).toBeNull();
    expect(getByText('Body content')).toBeTruthy();
  });

  it('shows component when visible has malformed rule (fail open)', () => {
    const registry = buildRegistry();
    const screen: SDUIScreen = {
      id: 'malformed_visible_test',
      context: {},
      body: [
        {
          type: 'heading',
          props: { text: 'Malformed visible' },
          visible: { rule: {} as any },
        },
      ],
    };
    const { getByText } = render(
      <ScreenRenderer screen={screen} registry={registry} />,
    );
    expect(getByText('Malformed visible')).toBeTruthy();
  });

  it('supports complex visibility rules with nested logic', () => {
    const registry = buildRegistry();
    const screen: SDUIScreen = {
      id: 'complex_visibility_test',
      context: { input: { points: 500 }, balance: { available: 1000 } },
      body: [
        {
          type: 'button',
          props: { label: 'Submit' },
          visible: {
            rule: {
              and: [
                { '>': [{ var: 'input.points' }, 0] },
                { '<=': [{ var: 'input.points' }, { var: 'balance.available' }] },
              ],
            },
          },
        },
      ],
    };
    const { getByText } = render(
      <ScreenRenderer screen={screen} registry={registry} />,
    );
    expect(getByText('Submit')).toBeTruthy();
  });

