    function buildInteractiveRegistry() {
      let reg = createRegistry();
      reg = registerComponent(reg, 'heading', HeadingAdapter);
      reg = registerComponent(reg, 'action_button', ActionButtonAdapter);
      reg = registerComponent(reg, 'context_display', ContextDisplayAdapter);
      return reg;
    }

